public class OrderProcessor {

    // Method to query the price of a product based on its name
    public static int getPrice(String productName, List<String> priceList) {
        for (String product : priceList) {
            String[] parts = product.split("–");
            if (parts[0].equals(productName)) {
                return Integer.parseInt(parts[1]);
            }
        }
        throw new IllegalArgumentException("Product not found in the list.");
    }

    public static void main(String[] args) {
        // Example usage
        List<String> priceList = List.of(
            "Apple–5.99",
            "Banana–0.79",
            "Cherry–3.49"
        );

        String orderString = "Apple – 2";
        String[] orderData = orderString.split("\\s+");
        int productDetails = orderData[0].split("–");
        int productPrice = priceList.get(productDetails[1]);
        int orderPrice = Integer.parseInt(orderData[1]) * productPrice;

        System.out.println("Order Price: " + orderPrice);
    }
}
